package kr.gampa.battlegrounds.combat; import java.util.*; public record BulletTrajectory(BallisticVector position,BallisticVector velocity,double gravity,double dragPerSecond){public BulletTrajectory step(double dt){double drag=Math.max(0,1-dragPerSecond*dt);BallisticVector v=new BallisticVector(velocity.x()*drag,velocity.y()*drag-gravity*dt,velocity.z()*drag);return new BulletTrajectory(position.add(v.multiply(dt)),v,gravity,dragPerSecond);}public static double dropAtDistance(double distance,double speed,double gravity,double drag){if(distance<0||speed<=0)throw new IllegalArgumentException();if(drag==0){double t=distance/speed;return .5*gravity*t*t;}BulletTrajectory b=new BulletTrajectory(new BallisticVector(0,0,0),new BallisticVector(speed,0,0),gravity,drag);for(int i=0;i<100000&&b.position.x()<distance;i++)b=b.step(.001);return -b.position.y();}public static BallisticVector clipSegment(BallisticVector from,BallisticVector to,double maxLength){if(maxLength<0)throw new IllegalArgumentException();double length=from.distance(to);return length<=maxLength?to:from.lerp(to,maxLength/length);}public static List<BallisticVector> sampleSegment(BallisticVector from,BallisticVector to,double spacing){if(spacing<=0)throw new IllegalArgumentException();double length=from.distance(to);if(length==0)return List.of();int count=(int)Math.ceil(length/spacing);List<BallisticVector> out=new ArrayList<>(count);for(int i=1;i<=count;i++)out.add(from.lerp(to,Math.min(1,i*spacing/length)));return out;}}